        "url": "https://wawamor.ec/sites/ecuador/files/styles/content_1200xh_/public/2024-09/vaignal-birth.webp?itok=48RPsTwS",
        "name": "Vaignal birth.jpg",
        "alt": "Mother and baby doing skin-to-skin"
