        "url": "https://wawamor.ec/sites/ecuador/files/styles/content_1200xh_/public/2025-06/52494253638_6f6aacc8af_c.webp?itok=Hy7X8mV_",
        "name": "52494253638_6f6aacc8af_c.jpg",
