        "url": "https://wawamor.ec/sites/ecuador/files/styles/content_1200xh_/public/2024-09/pain-relief-during-birth.webp?itok=8QZlwNXu",
        "name": "Pain relief during birth.jpg",
        "alt": "Woman using natural pain relief during labour"
