      "keywords": [4131, 1676, 2981, 4056],
      "meta_keywords": "soothing, love, self-regulation, nurturing care, responsive parenting, learning, development",
      "cover_image": {
        "url": "https://wawamor.ec/sites/ecuador/files/styles/content_1200xh_/public/2021-08/un0269380.webp?itok=EG5n775K",
        "name": "UN0269380.jpg",
        "alt": "Baby crying."
      },
