        "url": "https://wawamor.ec/sites/ecuador/files/styles/content_1200xh_/public/2025-05/chatgpt-image-4-may-2025-21_22_51.webp?itok=pFp1b0GY",
        "name": "ChatGPT Image 4 may 2025, 21_22_51.png",
